CODE_EXAMPLE:
public class Throttler {
  private long lastCallTime = 0;
  private long minInterval = 100;

  public void Throttle() {
    long now = DateTime.UtcNow.Ticks;
    if (now - lastCallTime < minInterval) {
      Thread.Sleep((int)((minInterval - (now - lastCallTime)) / 10000));
    }
    lastCallTime = DateTime.UtcNow.Ticks;
  }
}

UNIT_TEST_EXAMPLE:
[TestMethod]
public void Throttle_DelaysRequests_WhenNeeded() {
  var throttler = new Throttler();
  var sw = Stopwatch.StartNew();
  throttler.Throttle();
  throttler.Throttle();
  sw.Stop();
  Assert.IsTrue(sw.ElapsedMilliseconds >= 100);
}

[TestMethod]
public void Throttle_DoesNotThrow() {
  var throttler = new Throttler();
  throttler.Throttle();
}
